window.getResourceAsTextCache={};window.getResourceAsText=function(file){if(window.getResourceAsTextCache[file]==null){const resource=window.getResource(file);if(resource.startsWith('data:')){const base64=resource.split(',')[1];window.getResourceAsTextCache[file]=decodeURIComponent(escape(window.atob(base64)));}
else{const xhr=new XMLHttpRequest();xhr.open('GET',resource,false);xhr.send();window.getResourceAsTextCache[file]=xhr.responseText??null;}}
return window.getResourceAsTextCache[file];}
window.getResourceAsBase64=async function(file){const resource=window.getResource(file);if(resource.startsWith('data:')){return resource;}
else{const response=await fetch(resource);const blob=await response.blob();return await new Promise((resolve,reject)=>{const reader=new FileReader();reader.onloadend=()=>resolve(reader.result);reader.onerror=reject;reader.readAsDataURL(blob);});}}
