async function keyIsValid(key,value){if(value==null){return false;}
if(key=='primarycolor'||key=='secondarycolor'||key=='backgroundcolor'){return/^#[0-9a-fA-F]{6}${"$"}/.test(value);}
else if(key=='bools'){return/^(0|1){18,}${"$"}/.test(value);}
else if(key=='ui'||key=='uiblur'){return value>=0&&value<=100;}
else if(key=='menuwidth'){return value>=50&&value<=700;}
else if(key=='brightness'||key=='contrast'||key=='saturate'||key=='opacity'||key=='grayscale'||key=='sepia'||key=='invert'){return/^\d+%${"$"}/.test(value);}
else if(key=='huerotate'){return/^\d+deg${"$"}/.test(value);}
else if(key=='blur'){return/^\d+(\.\d+)?px${"$"}/.test(value);}
else if(key=='layout'){return value>=1&&value<=5;}
else if(key=='nicknames'){const json=parseJSON(value);if(json===null||!(json instanceof Array)){return false;}
let mayContainHTMLTag=false;let i=0;for(const nickname of json){if(nickname.length!=2&&nickname.length!=3){return false;}
if(/<\/?[a-z][\s\S]*>/i.test(nickname[0])||/<\/?[a-z][\s\S]*>/i.test(nickname[1])){mayContainHTMLTag=true;json[i][0]=sanitizeString(nickname[0]);json[i][1]=sanitizeString(nickname[1]);if(nickname.length==3&&/<\/?[a-z][\s\S]*>/i.test(nickname[2])){json[i][2]=sanitizeString(nickname[2]);}}
i++;}
if(mayContainHTMLTag){while(id('mod-message')){await new Promise(resolve=>setTimeout(resolve,50));}
modMessage('Onveilige instellingswaarde','Het lijkt erop dat de instellingswaarde voor "Nicknames" HTML-elementen bevat, waarmee er onveilige code op je computer uitgevoerd kan worden. Wil je deze HTML elementen weghalen voor de veiligheid?','Weghalen','Behouden',false,true);id('mod-message-action1').addEventListener('click',function(){set('nicknames',JSON.stringify(json));closeModMessage();saveReload(true);tn('sl-root',0).inert=false;if(tn('sl-modal',0)){tn('sl-modal',0).inert=false;}});id('mod-message-action2').addEventListener('click',function(){set('nicknames',value);closeModMessage();saveReload(true);tn('sl-root',0).inert=false;if(tn('sl-modal',0)){tn('sl-modal',0).inert=false;}});return null;}
return true;}
else if(key=='username'){if(/<\/?[a-z][\s\S]*>/i.test(value)){while(id('mod-message')){await new Promise(resolve=>setTimeout(resolve,50));}
modMessage('Onveilige instellingswaarde','Het lijkt erop dat de instellingswaarde voor "Username" HTML-elementen bevat, waarmee er onveilige code op je computer uitgevoerd kan worden. Wil je deze HTML elementen weghalen voor de veiligheid?','Weghalen','Behouden',false,true);id('mod-message-action1').addEventListener('click',function(){set('username',sanitizeString(value));closeModMessage();saveReload(true);tn('sl-root',0).inert=false;if(tn('sl-modal',0)){tn('sl-modal',0).inert=false;}});id('mod-message-action2').addEventListener('click',function(){set('username',value);closeModMessage();saveReload(true);tn('sl-root',0).inert=false;if(tn('sl-modal',0)){tn('sl-modal',0).inert=false;}});return null;}
return true;}
else if(key=='homework'||key=='letterbeoordelingen'){return parseJSON(value)!==null;}
else if(key=='icon'||key=='background'||key=='profilepic'||key=='customfont'){return value.startsWith('data:');}
else if(key=='backgroundtype'){return(value=='image'||value=='color'||value=='slideshow'||value=='live');}
else if(key=='fontname'){return fonts.includes(value);}
else if(key=='isbackgroundvideo'){return(value===true||value===false||value==='true'||value==='false');}
return true;}
