function getCompletedLevels(){const data=get('platformer-progress');return n(data)?{}:JSON.parse(data);}
function markLevelCompleted(levelIdx,coins){const progress=getCompletedLevels();if(!progress[levelIdx]||progress[levelIdx].coins<coins){progress[levelIdx]={completed:true,coins};set('platformer-progress',JSON.stringify(progress));}}
function getLevelCoins(levelIdx){const progress=getCompletedLevels();return progress[levelIdx]?.coins||0;}
function getTotalCoinsEarned(){const progress=getCompletedLevels();return Object.values(progress).reduce((sum,p)=>sum+(p.coins||0),0);}
