.getAttribute('stuck')==='false';const n1=Math.floor(Math.random()*5)+1;let n2=Math.floor(Math.random()*10);if(n1===5&&n2>=5)n2=4;const obj={type:'enemy',x,y,w:50,h:50,startX:x,startY:y,min:mn,max:mx,detectionR,detected:false,label:`${"$"}{n1},${"$"}{n2}`,ghost,texture,textureMode,textureFrames,textureFps,rotation,invertX,invertY,tex:null,stuck:stuck,vy:0,onGround:false};lvl.enemies.push(obj);lvl.drawOrder.push(obj);}else if(tag==='orb'){const obj={type:'orb',x,y,r:20,strength:parseFloat(c.getAttribute('strength'))||2.5,actTimer:0,ghost,texture,textureMode,textureFrames,textureFps,rotation,invertX,invertY,tex:null};lvl.orbs.push(obj);lvl.drawOrder.push(obj);}else if(tag==='movingPlatformUp'){const psy=parseFloat(c.getAttribute('startY'))||y;const pey=parseFloat(c.getAttribute('endY'))||y+300;const triggerMode=c.getAttribute('triggerMode')==='true';const triggerTimeout=parseFloat(c.getAttribute('triggerTimeout')??1.0);const returnTimeout=parseFloat(c.getAttribute('returnTimeout')??2.0);const obj={type:'mpUp',x,w,h,startY:psy,endY:pey,cy:psy,dir:1,ghost,oneWay,texture,textureMode,textureFrames,textureFps,rotation,invertX,invertY,tex:null,triggerMode,triggerTimeout,returnTimeout,triggerTimer:0,returnTimer:0,triggerState:'idle'};lvl.mpUp.push(obj);lvl.drawOrder.push(obj);}else if(tag==='movingPlatformRight'){const psx=parseFloat(c.getAttribute('startX'))||x;const pex=parseFloat(c.getAttribute('endX'))||x+300;const obj={type:'mpRight',y,w,h,startX:psx,endX:pex,cx:psx,dir:1,ghost,oneWay,texture,textureMode,textureFrames,textureFps,rotation,invertX,invertY,tex:null};lvl.mpRight.push(obj);lvl.drawOrder.push(obj);}else if(tag==='coin'){const r=parseFloat(c.getAttribute('r'))||14;const blue=c.getAttribute('blue')==='true';const obj={type:'coin',x,y,r,collected:false,bobTimer:Math.random()*Math.PI*2,ghost,texture,textureMode,textureFrames,textureFps,rotation,invertX,invertY,tex:null,blue};lvl.coins.push(obj);lvl.drawOrder.push(obj);}else if(tag==='checkpoint'){const obj={type: