return segs;}
const segments=parseSegments(c,bold,baseColor);const obj={type:'text',x,y,segments,baseFont,fontSize,fontFamily,bold,ghost};lvl.texts.push(obj);lvl.drawOrder.push(obj);}else if(tag==='portal'){const portalId=c.getAttribute('portal-id')||null;const toPortalId=c.getAttribute('to-portal-id')||null;const obj={type:'portal',x,y,w,h,portalId,toPortalId,cooldown:0,texture,textureMode,textureFrames,textureFps,rotation,invertX,invertY,tex:null};lvl.portals.push(obj);lvl.drawOrder.push(obj);}else if(tag==='key'){const keyId=c.getAttribute('keyId')||`key_${"$"}{Math.random()}`;const keyColor=c.getAttribute('color')||'#ffd700';const r=parseFloat(c.getAttribute('r'))||16;const obj={type:'key',x,y,origX:x,origY:y,r,keyId,keyColor,collected:false,bobTimer:Math.random()*Math.PI*2,ghost,_swapLocked:false,};lvl.keys.push(obj);lvl.drawOrder.push(obj);}else if(tag==='area'){const areaId=c.getAttribute('id')||`area_${"$"}{Math.random()}`;const checkpointX=c.getAttribute('checkpointX')!==null?parseFloat(c.getAttribute('checkpointX')):null;const checkpointY=c.getAttribute('checkpointY')!==null?parseFloat(c.getAttribute('checkpointY')):null;const obj={type:'area',x,y,w,h,areaId,checkpointX,checkpointY,triggered:false,};lvl.areas.push(obj);}else if(tag==='camera'){const areaId=c.getAttribute('areaId')||null;const lockX=c.getAttribute('lockX')==='true';const lockY=c.getAttribute('lockY')==='true';const targetCamX=c.getAttribute('targetCamX')!==null?parseFloat(c.getAttribute('targetCamX')):null;const targetCamY=c.getAttribute('targetCamY')!==null?parseFloat(c.getAttribute('targetCamY')):null;lvl.cameras.push({type:'camera',areaId,lockX,lockY,targetCamX,targetCamY});}else if(tag==='music'){const areaId=c.getAttribute('areaId')||null;const song=c.getAttribute('song')||null;const fadeDuration=parseFloat(c.getAttribute('fadeDuration'))||1.5;const restartOnDie=c.getAttribute('restartOnDie')==='true';lvl.musicTriggers.push({areaId,song,fadeDuration,fired:false,restartOnDie});}else if(tag==='enemySpawner'){const areaId=c.getAttribute('areaId')||null;const count=parseInt(c.getAttribute('count'))||1;const spawnX=parseFloat(c.getAttribute('x'))??0;const spawnY=parseFloat(c.getAttribute('y'))??0;const spawnSpread=parseFloat(c.getAttribute('spread'))||0;const mn=c.getAttribute('min')!==null?parseFloat(c.getAttribute('min')):null;const mx=c.getAttribute('max')!==null?parseFloat(c.getAttribute('max')):null;const detectionR=parseFloat(c.getAttribute('detectionRadius'))||200;const stuck=c.getAttribute('stuck')!=='false';const ghostSp=c.getAttribute('ghost')==='true';const textureSp=c.getAttribute('texture')||null;const textureModeSp=c.getAttribute('textureMode')||'tile';if(!lvl.enemySpawners)lvl.enemySpawners=[];lvl.enemySpawners.push({areaId,count,spawnX,spawnY,spread:spawnSpread,min:mn,max:mx,detectionR,stuck,ghost:ghostSp,texture:textureSp,textureMode:textureModeSp,textureFrames,textureFps,rotation,invertX,invertY,speed:parseFloat(c.getAttribute('speed'))||100,fired:false,});}else if(tag==='despawnEnemies'){lvl.despawnTriggers.push({areaId:c.getAttribute('areaId')||null,spawnerAreaId:c.getAttribute('spawnerAreaId')||null,fired:false,});}else if(tag==='playAgainButton'){lvl.playAgainText=c.textContent||lvl.playAgainText;}else if(tag==='closeGameButton'){lvl.closeGameText=c.textContent||lvl.closeGameText;}}
return lvl;}
async function loadLevelTextures(lvl){const all=[...lvl.floors,...lvl.walls,...lvl.lavas,...lvl.trampolines,...lvl.enemies,...lvl.orbs,...lvl.mpUp,...lvl.mpRight,...lvl.coins,...lvl.portals];await Promise.all(all.map(async obj=>{if(obj.texture){obj.tex=await loadTexture(obj.texture);if(obj.tex&&obj.textureMode==='tile'&&obj.w&&obj.h){if(obj.textureFrames>1){obj._animBakedFrames=bakeAnimatedTiledTexture(obj.tex,obj.w,obj.h,obj.textureFrames);}else{obj.bakedCanvas=bakeTiledTexture(obj.tex,obj.w,obj.h);}}}
if(obj.textureGhost)obj.texGhost=await loadTexture(obj.textureGhost);}));if(lvl.bgTexture){lvl._bgTexEntry=await loadTexture(lvl.bgTexture);}}
function bakeBg(lvl){const w=canvas.width,h=canvas.height;if(lvl._bgBaked&&lvl._bgBakedW===w&&lvl._bgBakedH===h){return lvl._bgBaked;}
const oc=new OffscreenCanvas(w,h);const octx=oc.getContext('2d');const top=lvl.bgColor||'#0f0f23';const bottom=lvl.bgColor2||(lvl.bgColor?lvl.bgColor:'#1a1a2e');const g=octx.createLinearGradient(0,0,0,h);g.addColorStop(0,top);g.addColorStop(1,bottom);octx.fillStyle=g;octx.fillRect(0,0,w,h);if(lvl._bgTexEntry){const tex=lvl._bgTexEntry;const mode=lvl.bgTextureMode;const alpha=lvl.bgTextureAlpha??1;octx.globalAlpha=alpha;if(mode==='tile'){const pat=octx.createPattern(tex.img,'repeat');octx.fillStyle=pat;octx.fillRect(0,0,w,h);}else if(mode==='stretch'){octx.drawImage(tex.img,0,0,w,h);}else if(mode==='cover'){const imgW=tex.img.naturalWidth,imgH=tex.img.naturalHeight;const scale=Math.max(w / imgW,h / imgH);const dw=imgW*scale,dh=imgH*scale;octx.drawImage(tex.img,(w-dw)/ 2,(h-dh)/ 2,dw,dh);}
octx.globalAlpha=1;}
lvl._bgBaked=oc;lvl._bgBakedW=w;lvl._bgBakedH=h;return oc;}
function bakeTiledTexture(texEntry,w,h){const oc=new OffscreenCanvas(w,h);const octx=oc.getContext('2d');const pat=octx.createPattern(texEntry.img,'repeat');octx.fillStyle=pat;octx.fillRect(0,0,w,h);return oc;}
function bakeAnimatedTiledTexture(texEntry,w,h,frameCount){const img=texEntry.img;const frameH=img.naturalHeight / frameCount;const frameW=img.naturalWidth;return Array.from({length:frameCount},(_,i)=>{const oc=new OffscreenCanvas(w,h);const octx=oc.getContext('2d');for(let ty=0;ty<h;ty+=frameH){for(let tx=0;tx<w;tx+=frameW){octx.drawImage(img,0,i*frameH,frameW,frameH,tx,ty,frameW,frameH);}}
return oc;});}
const levels=[];const parser=new DOMParser();for(let i=0;;i++){try{const resp=window.getResourceAsText(`data/the-dungeon/lvl-${"$"}{i}.xml`);const xml=parser.parseFromString(resp,'text/xml');if(xml.querySelector('parseerror'))break;const lvlParsed=parseLvl(xml,i);await loadLevelTextures(lvlParsed);levels.push(lvlParsed);}catch(e){break;}}
function populateLevelGrid(){const grid=document.getElementById('mod-level-grid');grid.innerHTML='';const progress=getCompletedLevels();const highestCompleted=Math.max(-1,...Object.keys(progress).map(k=>parseInt(k)));levels.forEach((level,idx)=>{const totalCoins=countLevelCoins(level);const earnedCoins=getLevelCoins(idx);const completed=progress[idx]?.completed||false;const locked=idx>highestCompleted+1;const bestTime=getLevelBestTime(idx);const card=document.createElement('div');card.className='mod-level-card';if(completed)card.classList.add('mod-level-done');if(locked)card.classList.add('mod-level-locked');if(locked){card.innerHTML=`

