for(const orb of lvl.orbs)orb.actTimer=0;portalCooldownTimer=0;snapCam=true;phase='playing';timing=true;if(musicAudio)musicAudio.play().catch(()=>{});},!hasUndo);drawBtn(bx,py2+84+(bh+gap)*3,bw,bh,'✕  Sluiten','#555',()=>endGame());const sliderX=px2+30;const sliderW=panelW-60;const sliderY1=py2+84+(bh+gap)*4+10;const sliderY2=sliderY1+52;for(const[label,vol,setVol,y]of[['Muziek',musicVolume,(v)=>{set('platformer-music-volume',v);musicVolume=v;if(musicAudio)musicAudio.volume=v;if(musicFading){const t=Math.min(1,musicFading.timer / musicFading.duration);if(musicFading.outAudio)musicFading.outAudio.volume=v*(1-t);if(musicFading.inAudio)musicFading.inAudio.volume=v*t;}},sliderY1],['Geluiden',sfxVolume,(v)=>{set('platformer-sfx-volume',v);sfxVolume=v;},sliderY2],]){ctx.fillStyle='#aaa';ctx.font='14px sans-serif';ctx.textAlign='left';ctx.textBaseline='middle';ctx.fillText(label,sliderX,y+8);const trackY=y+28;const trackH=6;ctx.fillStyle='#333';ctx.beginPath();ctx.roundRect(sliderX,trackY-trackH / 2,sliderW,trackH,3);ctx.fill();ctx.fillStyle='#5b9cf6';ctx.beginPath();ctx.roundRect(sliderX,trackY-trackH / 2,sliderW*vol,trackH,3);ctx.fill();const knobX=sliderX+sliderW*vol;ctx.fillStyle='#fff';ctx.beginPath();ctx.arc(knobX,trackY,9,0,Math.PI*2);ctx.fill();btns.push({x:sliderX,y:trackY-14,w:sliderW,h:28,cb:()=>{},_slider:true,_setVol:setVol,_sliderX:sliderX,_sliderW:sliderW,});}
