function drawLevelCompleteScreen(){ctx.save();ctx.shadowBlur=0;ctx.shadowColor='transparent';ctx.fillStyle='rgba(0,0,0,0.72)';ctx.fillRect(0,0,canvas.width,canvas.height);const panelW=380,panelH=340;const px2=canvas.width / 2-panelW / 2;const py2=canvas.height / 2-panelH / 2;ctx.fillStyle='rgba(15,15,35,0.97)';ctx.beginPath();ctx.roundRect(px2,py2,panelW,panelH,18);ctx.fill();ctx.strokeStyle='rgba(76,175,80,0.4)';ctx.lineWidth=1.5;ctx.beginPath();ctx.roundRect(px2,py2,panelW,panelH,18);ctx.stroke();ctx.textAlign='center';ctx.textBaseline='middle';ctx.fillStyle='#fce512';ctx.font='bold 36px sans-serif';ctx.fillText('✓ Level voltooid!',canvas.width / 2,py2+52);ctx.fillStyle='#9b9b9c';ctx.font='22px sans-serif';ctx.fillText(`Tijd: ${"$"}{levelCompletedTime.toFixed(1)}s`,canvas.width / 2,py2+102);const bestTime=getLevelBestTime(lvlIdx);if(bestTime!==null){const isNew=Math.abs(bestTime-levelCompletedTime)<0.05;ctx.fillStyle=isNew?'#4caf50':'#9b9b9c';ctx.font=isNew?'bold 18px sans-serif':'18px sans-serif';ctx.fillText(isNew?`🏆 Nieuwe beste tijd: ${"$"}{bestTime.toFixed(1)}s`:`Beste tijd: ${"$"}{bestTime.toFixed(1)}s`,canvas.width / 2,py2+138);}
