function drawWinScreen(){ctx.save();ctx.shadowBlur=0;ctx.shadowColor='transparent';ctx.fillStyle='rgba(0,0,0,0.72)';ctx.fillRect(0,0,canvas.width,canvas.height);ctx.textAlign='center';ctx.textBaseline='middle';ctx.fillStyle='#fce512';ctx.font='bold 56px sans-serif';ctx.fillText('🎉 Voltooid! 🎉',canvas.width / 2,canvas.height / 2-90);ctx.fillStyle='#9b9b9c';ctx.font='30px sans-serif';ctx.fillText(`Tijd: ${"$"}{elapsed.toFixed(1)}s`,canvas.width / 2,canvas.height / 2-30);ctx.fillStyle=COL.coin;ctx.font='bold 28px sans-serif';const totalPossible=levels.reduce((sum,l)=>sum+countLevelCoins(l),0);ctx.fillText(`🪙 Munten: ${"$"}{sessionCoins} / ${"$"}{totalPossible}`,canvas.width / 2,canvas.height / 2+68);const bw=300,bh=54,bx=canvas.width / 2-bw / 2;drawBtn(bx,canvas.height / 2+110,bw,bh,lvl?.playAgainText||'Opnieuw spelen','#3f8541',()=>{elapsed=0;timing=true;sessionCoins=0;sessionTotalCoins=0;loadLvl(0);});drawBtn(bx,canvas.height / 2+180,bw,bh,'Menu','#555',()=>endGame());ctx.restore();playSfx('tada');}
function drawHUD(){id('mod-playtime').textContent=`Tijd: ${"$"}{elapsed.toFixed(0)}s`;const totalPossible=levels.reduce((sum,l)=>sum+countLevelCoins(l),0);id('mod-coins-hud').textContent=totalPossible>0?`🪙 ${"$"}{sessionCoins}`:'';}
function redrawObj(o){if(o.type==='floor'){if(isVisible(o.x,o.y,o.w,o.h))ghostFillRect(o,o.x,o.y,o.w,o.h,COL.floor);}else if(o.type==='wall'){const drawY=o.riseWithId?o.riseCurrentY:o.y;const drawH=o.riseWithId?o.riseCurrentH:o.h;if(isVisible(o.x,drawY,o.w,drawH)){if(o.keyId){drawKeyDoor(o);}else if(o.closeOnAreaId){drawAreaCloseWall(o);}else{ghostFillRect(o,o.x,drawY,o.w,drawH,COL.wall);}}}else if(o.type==='lava'){const lh=o.flowUp?o.currentH:o.h;if(isVisible(o.x,o.y,o.w,lh))ghostFillRect(o,o.x,o.y,o.w,lh,COL.lava);}else if(o.type==='trampoline'){if(isVisible(o.x,o.y,o.w,o.h))ghostFillRect(o,o.x,o.y,o.w,o.h,COL.tramp,8);}else if(o.type==='mpUp'){if(isVisible(o.x,o.cy,o.w,o.h))ghostFillRect(o,o.x,o.cy,o.w,o.h,COL.floor);}else if(o.type==='mpRight'){if(isVisible(o.cx,o.y,o.w,o.h))ghostFillRect(o,o.cx,o.y,o.w,o.h,COL.floor);}else if(o.type==='enemy'){if(isVisible(o.x,o.y,o.w,o.h))drawEnemy(o);}else if(o.type==='orb'){if(isVisible(o.x-o.r,o.y-o.r,o.r*2,o.r*2))drawOrb(o);}else if(o.type==='coin'){if(isVisible(o.x-o.r,o.y-o.r,o.r*2,o.r*2))drawCoin(o);}else if(o.type==='key'){if(isVisible(o.x-o.r,o.y-o.r,o.r*2,o.r*2))drawKey(o);}else if(o.type==='checkpoint'){if(isVisible(o.x,o.y,FLAG_W,FLAG_H))drawCheckpoint(o);}else if(o.type==='end'){if(isVisible(o.x,o.y,o.w,o.h))drawEnd(o);}else if(o.type==='text'){if(isVisible(o.x-400,o.y-40,800,80))drawText(o);}else if(o.type==='portal'){if(isVisible(o.x,o.y,o.w,o.h))drawPortal(o);}}
function render(dt){btns.length=0;if(!lvl)return;drawBg();const floorCanvasY=wy(0,0);ctx.save();ctx.beginPath();ctx.rect(0,0,canvas.width,floorCanvasY);ctx.clip();const activeGhostWalls=lvl.walls.filter(w=>w.ghost&&w.opaque&&w.playerOverlap);const ghostWallRevealSets=activeGhostWalls.map(gw=>({wall:gw,objectsBehind:lvl.drawOrder.slice(0,lvl.drawOrder.indexOf(gw)),}));for(const o of lvl.drawOrder){if(o.type==='floor'){if(isVisible(o.x,o.y,o.w,o.h))ghostFillRect(o,o.x,o.y,o.w,o.h,COL.floor);}else if(o.type==='wall'){const drawY=o.riseWithId?o.riseCurrentY:o.y;const drawH=o.riseWithId?o.riseCurrentH:o.h;if(isVisible(o.x,drawY,o.w,drawH)){if(o.keyId){drawKeyDoor(o);}else if(o.closeOnAreaId){drawAreaCloseWall(o);}else{ghostFillRect(o,o.x,drawY,o.w,drawH,COL.wall);}}}else if(o.type==='lava'){const lh=o.flowUp?o.currentH:o.h;if(isVisible(o.x,o.y,o.w,lh))ghostFillRect(o,o.x,o.y,o.w,lh,COL.lava);}else if(o.type==='trampoline'){if(isVisible(o.x,o.y,o.w,o.h))ghostFillRect(o,o.x,o.y,o.w,o.h,COL.tramp,8);}else if(o.type==='mpUp'){if(isVisible(o.x,o.cy,o.w,o.h))ghostFillRect(o,o.x,o.cy,o.w,o.h,COL.floor);}else if(o.type==='mpRight'){if(isVisible(o.cx,o.y,o.w,o.h))ghostFillRect(o,o.cx,o.y,o.w,o.h,COL.floor);}else if(o.type==='enemy'){if(isVisible(o.x,o.y,o.w,o.h))drawEnemy(o);}else if(o.type==='orb'){if(isVisible(o.x-o.r,o.y-o.r,o.r*2,o.r*2))drawOrb(o);}else if(o.type==='coin'){if(isVisible(o.x-o.r,o.y-o.r,o.r*2,o.r*2))drawCoin(o);}else if(o.type==='key'){if(isVisible(o.x-o.r,o.y-o.r,o.r*2,o.r*2))drawKey(o);}else if(o.type==='checkpoint'){if(isVisible(o.x,o.y,FLAG_W,FLAG_H))drawCheckpoint(o);}else if(o.type==='end'){if(isVisible(o.x,o.y,o.w,o.h))drawEnd(o);}else if(o.type==='text'){if(isVisible(o.x-400,o.y-40,800,80))drawText(o);}else if(o.type==='portal'){if(isVisible(o.x,o.y,o.w,o.h))drawPortal(o);}}
if(phase==='dying')drawDeathSlices();else drawPlayer();for(const{wall:gw,objectsBehind}of ghostWallRevealSets){if(!isVisible(gw.x,gw.y,gw.w,gw.h))continue;if(!gw.playerOverlap)continue;ctx.save();ctx.beginPath();ctx.rect(wx(gw.x),wy(gw.y,gw.h),gw.w,gw.h);ctx.clip();for(const o of objectsBehind)redrawObj(o);if(phase==='dying')drawDeathSlices();else drawPlayer();ctx.restore();}
drawCoinPopups();ctx.restore();drawHUD();drawDescription();drawDoorMessage();if(phase==='paused')drawPauseScreen();if(phase==='levelComplete')drawLevelCompleteScreen();if(phase==='win')drawWinScreen();drawDebug(dt);}
function createDeathSlices(){deathSlices=[];const count=6;const sliceH=PH / count;const col=getComputedStyle(document.documentElement).getPropertyValue('--bg-primary-normal').trim()||'#ffffff';for(let i=0;i<count;i++){deathSlices.push({worldX:px,worldYBottom:py+PH-(i+1)*sliceH,localY:i*sliceH,h:sliceH,vx:(Math.random()-0.5)*700,vy:200+Math.random()*500,rot:0,rotV:(Math.random()-0.5)*18,col,});}}
function drawDeathSlices(){const alpha=Math.max(0,deathTimer / DEATH_DUR);for(const s of deathSlices){const sx=wx(s.worldX);const sy=wy(s.worldYBottom,s.h);ctx.save();ctx.globalAlpha=alpha;ctx.translate(sx+PW / 2,sy+s.h / 2);ctx.rotate(s.rot);ctx.beginPath();ctx.rect(-PW / 2,-s.h / 2,PW,s.h);ctx.clip();ctx.translate(-PW / 2,-s.h / 2-s.localY);ctx.fillStyle=s.col;ctx.fill(PLAYER_PATH);ctx.restore();}
ctx.globalAlpha=1;}
let lastTs=null;function loop(ts){if(!gameAlive)return;const dt=lastTs===null?0.016:Math.min((ts-lastTs)/ 1000,0.05);lastTs=ts;if(timing&&phase==='playing')elapsed+=dt;update(dt);render(dt);requestAnimationFrame(loop);}
function playSfx(name){if(!sfxPool[name])sfxPool[name]=[];const pool=sfxPool[name];let a=pool.find(x=>x.paused||x.ended);if(!a){a=new Audio(window.getAudioUrl(name));pool.push(a);}
a.currentTime=0;a.volume=sfxVolume;a.play().catch(()=>{});}
async function openCreditsPopup(){function mdInline(str){return str.replace(/`([^`]+)`/g,'<code>${"$"}1</code>').replace(/\*\*([^*]+)\*\*/g,'<strong>${"$"}1</strong>').replace(/\[([^\]]+)\]\((https?:\/\/[^)]+)\)/g,'<a href="${"$"}2" target="_blank" rel="noopener">${"$"}1</a>');}
const contributors={"levkris":"https:\/\/avatars.githubusercontent.com\/u\/105733478?s=64&v=4"};let musicRows='';let sfxRows='';let textureRows='';try{const md=window.getResourceAsText('data/the-dungeon/credits.md');const lines=md.split('\n');let section=null;for(const raw of lines){const line=raw.trimEnd();const h=line.match(/^##\s+(.*)/);if(h){const title=h[1].trim();if(/music/i.test(title))section='music';else if(/sound/i.test(title))section='sfx';else if(/textures/i.test(title))section='textures';else section=null;continue;}
if(/^---+${"$"}/.test(line)){section=null;continue;}
if(section==='music'&&line.startsWith('|')){const cells=line.split('|').map(c=>c.trim()).filter(Boolean);if(cells.length<4)continue;if(/^[-:\s]+${"$"}/.test(cells[0])||/bestand|file/i.test(cells[0]))continue;musicRows+=`<tr>

                        <td>${"$"}{mdInline(cells[0])}</td>

                        <td>${"$"}{mdInline(cells[1])}</td>

                        <td>${"$"}{mdInline(cells[2])}</td>

                        <td>${"$"}{mdInline(cells[3])}</td>

                    </tr>`;}
if(section==='sfx'&&line.startsWith('|')){const cells=line.split('|').map(c=>c.trim()).filter(Boolean);if(cells.length<2)continue;if(/^[-:\s]+${"$"}/.test(cells[0])||/bestand|file/i.test(cells[0]))continue;sfxRows+=`<tr>

                        <td>${"$"}{mdInline(cells[0])}</td>

                        <td>${"$"}{mdInline(cells[1])}</td>

                    </tr>`;}
if(section==='textures'&&line.startsWith('|')){const cells=line.split('|').map(c=>c.trim()).filter(Boolean);if(cells.length<2)continue;if(/^[-:\s]+${"$"}/.test(cells[0])||/bestand|file/i.test(cells[0]))continue;textureRows+=`<tr>

                        <td>${"$"}{mdInline(cells[0])}</td>

                        <td>${"$"}{mdInline(cells[1])}</td>

                    </tr>`;}}}catch(e){console.warn('Could not load credits.md',e);}
let contributorHTML='';for(const[key,value]of Object.entries(contributors)){contributorHTML+=`

            <a class="mod-credits-gh-pill" href="https://github.com/${"$"}{sanitizeString(key)}/" target="_blank" rel="noopener">

                <img src="${"$"}{sanitizeString(value)}" alt="${"$"}{sanitizeString(key)}" class="mod-credits-gh-avatar">

                <span class="mod-credits-gh-name">${"$"}{sanitizeString(key)}</span>

                ${"$"}{window.getIcon('github', 'mod-credits-gh-icon', 'currentColor')}

            </a>

            `;}
const overlay=document.createElement('div');overlay.className='mod-coming-soon-overlay';overlay.id='mod-credits-overlay';overlay.innerHTML=`

            <div class="mod-credits-box">

                <button class="mod-credits-close" id="mod-credits-close" aria-label="Sluiten">✕</button>



                <div class="mod-credits-header">

                    <span class="mod-credits-header-icon">📜</span>

                    <h2 class="mod-credits-title">Credits</h2>

                </div>



                <div class="mod-credits-scroll">



                    <section class="mod-credits-section">

                        <h3 class="mod-credits-section-title">👾 Creator of The Dungeon</h3>

                        <div class="mod-credits-gh-pills">${"$"}{contributorHTML}</div>

                    </section>

                    <div class="mod-credits-divider"></div>



                    ${"$"}{musicRows ? `<section class="mod-credits-section"><h3 class="mod-credits-section-title">🎵 Muziek</h3><table class="mod-credits-table"><thead><tr><th>Bestand</th><th>Titel</th><th>Artiest</th><th>Licentie</th></tr></thead><tbody>${"$"}{musicRows}</tbody></table></section><div class="mod-credits-divider"></div>` : ''}



                    ${"$"}{sfxRows ? `<section class="mod-credits-section"><h3 class="mod-credits-section-title">🔊Geluidseffecten</h3><table class="mod-credits-table"><thead><tr><th>Bestand</th><th>Bron</th></tr></thead><tbody>${"$"}{sfxRows}</tbody></table></section><div class="mod-credits-divider"></div>` : ''}



                    ${"$"}{textureRows ? `<section class="mod-credits-section"><h3 class="mod-credits-section-title">🌱Textures</h3><table class="mod-credits-table"><thead><tr><th>Bestand</th><th>Bron</th></tr></thead><tbody>${"$"}{textureRows}</tbody></table></section>` : ''}



                </div>

            </div>

        `;document.body.appendChild(overlay);const close=()=>overlay.remove();document.getElementById('mod-credits-close').addEventListener('click',close);overlay.addEventListener('click',e=>{if(e.target===overlay)close();});}}
