ctx.clearRect(0,0,canvas.width,canvas.height);ctx.restore();spawnTimer+=dt;const spawnRate=Math.max(300,1000-score*2);if(spawnTimer>spawnRate){const type=Math.random();let text,isBad,worth;if(type>0.9){text='⭐';isBad=false;worth=50;}else if(type>0.7){text=(Math.floor(Math.random()*45)+55)/ 10;text=text.toFixed(1);isBad=false;worth=5;}else{text=(Math.floor(Math.random()*40)+10)/ 10;text=text.toFixed(1);isBad=true;worth=10;}
enemies.push({x:Math.random()*(canvas.width-50)+25,y:-50,text:text,isBad,worth,health:isBad?1:1,maxHealth:isBad?1:1,speed:Math.random()*2+1+(score / 100)});spawnTimer=0;}
if(Math.random()<0.002&&powerups.length<2){const types=['❤️','💰','⚡'];powerups.push({x:Math.random()*(canvas.width-50)+25,y:-30,type:types[Math.floor(Math.random()*types.length)],speed:2});}
for(let i=0;i<particles.length;i++){let p=particles[i];p.x+=p.vx;p.y+=p.vy;p.vy+=0.2;p.life-=0.02;ctx.globalAlpha=Math.max(0,p.life);ctx.fillStyle=p.color;ctx.fillRect(p.x,p.y,4,4);if(p.life<=0){particles.splice(i,1);i--;}}
ctx.globalAlpha=1;for(let i=0;i<projectiles.length;i++){let p=projectiles[i];p.x+=p.vx;p.y+=p.vy;if(p.color==='rainbow'){const hue=(Date.now()/ 10)%360;ctx.fillStyle=`hsl(${"$"}{hue}, 100%, 50%)`;}else{ctx.fillStyle=p.color;}
ctx.shadowBlur=15;ctx.shadowColor=ctx.fillStyle;ctx.beginPath();ctx.arc(p.x,p.y,6,0,Math.PI*2);ctx.fill();ctx.shadowBlur=0;if(p.y<-10){projectiles.splice(i,1);i--;}}
ctx.font='bold 32px Arial';ctx.textAlign='center';for(let i=0;i<enemies.length;i++){let e=enemies[i];e.y+=e.speed;ctx.fillStyle=e.isBad?'#ff4444':'#44ff44';ctx.shadowBlur=10;ctx.shadowColor=ctx.fillStyle;ctx.fillText(e.text,e.x,e.y);ctx.shadowBlur=0;if(e.health<e.maxHealth){ctx.fillStyle='#333';ctx.fillRect(e.x-20,e.y-40,40,5);ctx.fillStyle='#ff0000';ctx.fillRect(e.x-20,e.y-40,40*(e.health / e.maxHealth),5);}
if(e.y>canvas.height){enemies.splice(i,1);i--;if(e.isBad){lives--;combo=0;shake=10;id('gd-lives').innerText=lives;id('gd-combo').innerText=combo;if(lives<=0){gameRunning=false;const coinsEarned=Math.floor(score / 10);coins+=coinsEarned;savedData.coins=coins;id('grade-defender-shop-btn').classList.remove('active');id('grade-defender-gameover').classList.add('active');id('gd-final-score').innerText=Math.floor(score);id('gd-coins-earned').innerText=coins-coinsAtStart;id('gd-coins').innerText=coins;id('gd-high-score').innerText=Math.max(score,savedData.highScore);saveData();}}}
for(let j=0;j<projectiles.length;j++){let p=projectiles[j];let dist=Math.hypot(p.x-e.x,p.y-e.y);if(dist<35){e.health-=p.damage;createParticles(e.x,e.y,e.isBad?'#ff4444':'#44ff44',10);if(p.splash){for(let k=0;k<enemies.length;k++){if(k!==i){let splashDist=Math.hypot(enemies[k].x-e.x,enemies[k].y-e.y);if(splashDist<p.splash){enemies[k].health-=p.damage / 2;createParticles(enemies[k].x,enemies[k].y,'#ff9900',5);}}}}
projectiles.splice(j,1);if(e.health<=0){enemies.splice(i,1);i--;if(e.isBad){score+=e.worth*(1+combo*0.1);combo++;shake=3;}else{score=Math.max(0,score-20);combo=0;}
