break;}}}
for(let i=0;i<powerups.length;i++){let p=powerups[i];p.y+=p.speed;ctx.font='bold 30px Arial';ctx.fillStyle='#fff';ctx.fillText(p.type,p.x,p.y);if(p.y>canvas.height){powerups.splice(i,1);i--;continue;}
if(Math.hypot(p.x-playerX,p.y-(canvas.height-50))<40){if(p.type==='❤️')lives=Math.min(10,lives+1);if(p.type==='💰')coins+=10;if(p.type==='⚡')combo+=5;createParticles(p.x,p.y,'#ffd700',30);id('gd-lives').innerText=lives;id('gd-coins').innerText=coins;id('gd-combo').innerText=combo;powerups.splice(i,1);i--;}}
ctx.save();ctx.translate(playerX,canvas.height-50);if(logoImg.complete&&logoImg.width>0){ctx.drawImage(logoImg,-30,-30,60,60);}else{ctx.fillStyle='#fff';ctx.fillRect(-25,0,50,20);ctx.fillRect(-5,-20,10,20);}
